document.addEventListener("DOMContentLoaded",()=>{let t=20;const e=document.getElementById("timer"),n=document.getElementById("skipBtn"),a=setInterval(()=>{t--,e.textContent=t,t<=0&&(clearInterval(a),o("completed"))},1e3);function o(t){const e=new Date,n=`${e.getFullYear()}-${String(e.getMonth()+1).padStart(2,"0")}-${String(e.getDate()).padStart(2,"0")}`;chrome.storage.local.get(["eyeGuardHistory"],e=>{let a=e.eyeGuardHistory||[];a.push({id:"eg-"+Date.now()+"-"+Math.random().toString(36).substr(2,9),date:n,timestamp:Date.now(),status:t}),chrome.storage.local.set({eyeGuardHistory:a},()=>{window.close()})})}n.addEventListener("click",()=>{clearInterval(a),o("skipped")})});